// Control-plane transport.proto encode/decode (gateway side, M20). Single source of truth =
// ../../contracts/transport.proto (shared with gameserver / client), generated by ts-proto (ADR-023 P3).
//
// The gateway only recognises the control-plane subset: decodes room_create/join/ready/start/leave + ping;
// encodes room_state / room_error / match_found / pong. Lockstep messages (cmd_submit /
// frame_batch / conn_* / match_*) belong to the data plane, handled by gameserver; decoded as 'unknown' and ignored here.
import {
  Envelope,
  ServerMsg as ProtoServerMsg,
  FriendUpdateKind,
} from './generated/transport';

export const RoomPhase = {
  WAITING: 0,
  READY: 1,
  COUNTDOWN: 2,
  IN_MATCH: 3,
  OVER: 4,
} as const;
export type RoomPhaseVal = (typeof RoomPhase)[keyof typeof RoomPhase];

export const MatchMode = {
  FRIENDLY: 0,
  RANKED: 1,
} as const;
export type MatchModeVal = (typeof MatchMode)[keyof typeof MatchMode];

export type ClientMsg =
  | { case: 'room_create'; mode: number; deck: string[] }
  | { case: 'room_join'; code: string; deck: string[] }
  | { case: 'room_ready'; ready: boolean }
  | { case: 'room_leave' }
  | { case: 'room_start' }
  | { case: 'ping' }
  | { case: 'client_caps'; canJudge: boolean }
  | {
      case: 'judge_verdict';
      requestId: string;
      stateHash: string;
      winnerSide: number;
      ok: boolean;
      stars: number;
      statsJson: string;
    }
  | { case: 'unknown' };

export interface PlayerSlotOut {
  side: number;
  name: string;
  ready: boolean;
  connected: boolean;
  publicId: string;
}
export interface FrameCmdsOut {
  frame: number;
  cmds: { side: number; commands: Uint8Array }[];
}
export type ServerMsg =
  | { case: 'room_state'; code: string; players: PlayerSlotOut[]; phase: number }
  | { case: 'match_found'; gameUrl: string; ticket: string }
  | { case: 'match_bot'; seed: number; opponentName: string; elo: number; difficulty: string }
  | { case: 'room_error'; code: string; message: string }
  | {
      case: 'judge_request';
      requestId: string;
      seed: number;
      mode: number;
      endFrame: number;
      frames: FrameCmdsOut[];
      levelId: string;
      pveUpgrades: Record<string, number>;
      unitLevels: Record<string, number>;
      topDeck: string[];
      bottomDeck: string[];
    }
  | { case: 'friend_presence'; publicId: string; online: boolean }
  | { case: 'friend_request'; requestId: string; fromPublicId: string; fromName: string; message: string }
  | { case: 'friend_update'; publicId: string; added: boolean }
  | { case: 'chat_message'; convId: string; fromPublicId: string; fromName: string; body: string; ts: number }
  | { case: 'mail_new'; mailId: string; hasAttachment: boolean }
  | {
      case: 'march_update';
      marchId: string;
      marchKind: string;
      fromTile: string;
      toTile: string;
      arriveAt: number;
      status: string;
    }
  | {
      case: 'tile_update';
      tileId: string;
      type: string;
      level: number;
      ownerPublicId: string;
      ownerName: string;
      familyId: string;
      protectedUntil: number;
    }
  | {
      case: 'under_attack';
      tile: string;
      attackerName: string;
      attackerPublicId: string;
      arriveAt: number;
      troopsHint: number;
    }
  | {
      case: 'siege_result';
      siegeId: string;
      marchId: string;
      tile: string;
      outcome: string;
      lootSummary: string;
      replayRef: string;
    }
  | { case: 'family_msg'; familyId: string; fromPublicId: string; fromName: string; body: string; ts: number }
  | { case: 'sect_msg'; sectId: string; fromPublicId: string; fromName: string; body: string; ts: number }
  | { case: 'nation_msg'; worldId: string; fromPublicId: string; fromName: string; body: string; ts: number }
  | { case: 'pong' };

export function decodeClient(buf: Uint8Array): ClientMsg {
  const env = Envelope.decode(buf);
  const client = env.client;
  if (!client) return { case: 'unknown' };

  if (client.roomCreate) {
    return { case: 'room_create', mode: client.roomCreate.mode, deck: client.roomCreate.deck };
  }
  if (client.roomJoin) return { case: 'room_join', code: client.roomJoin.code, deck: client.roomJoin.deck };
  if (client.roomReady) return { case: 'room_ready', ready: client.roomReady.ready };
  if (client.roomLeave !== undefined) return { case: 'room_leave' };
  if (client.roomStart !== undefined) return { case: 'room_start' };
  if (client.ping !== undefined) return { case: 'ping' };
  if (client.clientCaps) return { case: 'client_caps', canJudge: client.clientCaps.canJudge };
  if (client.judgeVerdict) {
    const v = client.judgeVerdict;
    return {
      case: 'judge_verdict',
      requestId: v.requestId,
      stateHash: v.stateHash,
      winnerSide: v.winnerSide,
      ok: v.ok,
      stars: v.stars,
      statsJson: v.statsJson,
    };
  }
  return { case: 'unknown' };
}

export function encodeServer(msg: ServerMsg): Uint8Array {
  let server: ProtoServerMsg;
  switch (msg.case) {
    case 'room_state':
      server = {
        roomState: {
          code: msg.code,
          players: msg.players.map((p) => ({
            side: p.side,
            name: p.name,
            ready: p.ready,
            connected: p.connected,
            publicId: p.publicId,
          })),
          phase: msg.phase,
        },
      };
      break;
    case 'match_found':
      server = { matchFound: { gameUrl: msg.gameUrl, ticket: msg.ticket } };
      break;
    case 'match_bot':
      server = { matchBot: { seed: msg.seed, opponentName: msg.opponentName, elo: msg.elo, difficulty: msg.difficulty } };
      break;
    case 'room_error':
      server = { roomError: { code: msg.code, message: msg.message } };
      break;
    case 'judge_request':
      server = {
        judgeRequest: {
          requestId: msg.requestId,
          seed: msg.seed,
          mode: msg.mode,
          endFrame: msg.endFrame,
          frames: msg.frames.map((f) => ({
            frame: f.frame,
            cmds: f.cmds.map((c) => ({ side: c.side, commands: c.commands })),
          })),
          levelId: msg.levelId,
          pveUpgrades: msg.pveUpgrades,
          unitLevels: msg.unitLevels,
          defenseJson: '',
          topDeck: msg.topDeck,
          bottomDeck: msg.bottomDeck,
        },
      };
      break;
    case 'friend_presence':
      server = { friendPresence: { publicId: msg.publicId, online: msg.online } };
      break;
    case 'friend_request':
      server = { friendRequest: { requestId: msg.requestId, fromPublicId: msg.fromPublicId, fromName: msg.fromName, message: msg.message } };
      break;
    case 'friend_update':
      server = { friendUpdate: { publicId: msg.publicId, kind: msg.added ? FriendUpdateKind.ADDED : FriendUpdateKind.REMOVED } };
      break;
    case 'chat_message':
      server = { chatMessage: { convId: msg.convId, fromPublicId: msg.fromPublicId, fromName: msg.fromName, body: msg.body, ts: msg.ts } };
      break;
    case 'mail_new':
      server = { mailNew: { mailId: msg.mailId, hasAttachment: msg.hasAttachment } };
      break;
    case 'march_update':
      server = { marchUpdate: { marchId: msg.marchId, kind: msg.marchKind, fromTile: msg.fromTile, toTile: msg.toTile, arriveAt: msg.arriveAt, status: msg.status } };
      break;
    case 'tile_update':
      server = { tileUpdate: { tileId: msg.tileId, type: msg.type, level: msg.level, ownerPublicId: msg.ownerPublicId, ownerName: msg.ownerName, familyId: msg.familyId, protectedUntil: msg.protectedUntil } };
      break;
    case 'under_attack':
      server = { underAttack: { tile: msg.tile, attackerName: msg.attackerName, attackerPublicId: msg.attackerPublicId, arriveAt: msg.arriveAt, troopsHint: msg.troopsHint } };
      break;
    case 'siege_result':
      server = { siegeResult: { siegeId: msg.siegeId, marchId: msg.marchId, tile: msg.tile, outcome: msg.outcome, lootSummary: msg.lootSummary, replayRef: msg.replayRef } };
      break;
    case 'family_msg':
      server = { familyMsg: { familyId: msg.familyId, fromPublicId: msg.fromPublicId, fromName: msg.fromName, text: msg.body, ts: msg.ts } };
      break;
    case 'sect_msg':
      server = { sectMsg: { sectId: msg.sectId, fromPublicId: msg.fromPublicId, fromName: msg.fromName, text: msg.body, ts: msg.ts } };
      break;
    case 'nation_msg':
      server = { nationMsg: { worldId: msg.worldId, fromPublicId: msg.fromPublicId, fromName: msg.fromName, text: msg.body, ts: msg.ts } };
      break;
    case 'pong':
      server = { pong: {} };
      break;
  }
  return Envelope.encode(Envelope.fromPartial({ server })).finish();
}
